import { Link, useNavigate } from "react-router-dom";

export default function Navbar() {
  const navigate = useNavigate();
  const isLogged = localStorage.getItem("token"); // check if user is logged in

  const logout = () => {
    localStorage.clear();
    navigate("/login"); // after logout, go to login page
  };

  return (
    <nav style={{ padding: 10, background: "#222", color: "#fff" }}>
      <Link to="/" style={{ color: "#fff", marginRight: 10 }}>Home</Link>

      {isLogged ? (
        <>
          <Link to="/vehicles" style={{ color: "#fff", marginRight: 10 }}>Vehicles</Link>
          <Link to="/appointments" style={{ color: "#fff", marginRight: 10 }}>Appointments</Link>
          <button onClick={logout} style={{ padding: "5px 10px", cursor: "pointer" }}>Logout</button>
        </>
      ) : (
        <>
          <Link to="/login" style={{ color: "#fff", marginRight: 10 }}>Login</Link>
          <Link to="/register" style={{ color: "#fff" }}>Register</Link>
        </>
      )}
    </nav>
  );
}
